files.content:
:host {
  display: inline-flex;
  max-width: 80%;
  box-sizing: border-box;
  -webkit-user-select: text;
  user-select: text;
}

:host(.message-bubble--ghost) {
  display: block;
  max-width: 100%;
}

.message-bubble {
  min-width: 0;
  padding-block: var(--dimension-space-100);
  padding-inline: calc(var(--dimension-space-100) + var(--dimension-space-025));
  border-radius: var(--dimension-radius-050);
  background: transparent;
  color: var(--color-foreground-primary);
  font-family: var(--typography-font-family);
  font-size: var(--typography-fontsize-md);
  line-height: var(--typography-lineheight-md);
  font-weight: var(--typography-weight-regular);
  letter-spacing: var(--typography-letterspacing-negative-half);
  box-sizing: border-box;
  overflow-wrap: anywhere;
}

:host(.message-bubble--primary) .message-bubble {
  background: var(--color-translucent-translucent);
  color: var(--color-foreground-primary);
  box-shadow: inset 0 0 0 var(--dimension-stroke-width-012) var(--color-border-tertiary);
}

:host(.message-bubble--secondary) .message-bubble {
  box-shadow: inset 0 0 0 var(--dimension-stroke-width-012) var(--color-border-tertiary);
}

:host(.message-bubble--ghost) .message-bubble {
  padding-inline: 0;
  background: transparent;
  border-radius: 0;
}

import { Component, h, Host, Prop } from '@stencil/core';

export type MessageBubbleVariant = 'primary' | 'secondary' | 'ghost';

@Component({
  tag: 'ds-message-bubble',
  styleUrl: 'MessageBubble.css',
  scoped: true,
})
export class MessageBubble {
  @Prop() variant: MessageBubbleVariant = 'secondary';

  render() {
    return (
      <Host class={`message-bubble--${this.variant}`}>
        <div class="message-bubble"><slot /></div>
      </Host>
    );
  }
}
